try {
  const nodeWebhook = $node["Webhook"];
  const nodeGrouping = $node["Agrupar_Mensajes_V2"];
  const nodeIA = $("IA_Analisis_Total");

  const webhookBody = (nodeWebhook && nodeWebhook.json && nodeWebhook.json.body) ? nodeWebhook.json.body : {};
  const historyBody = (nodeGrouping && nodeGrouping.json && nodeGrouping.json.body) ? nodeGrouping.json.body : {};

  let contextData = webhookBody.context_data || {};

  // --- CORRECCIÓN DE DATOS ESCAPADOS ---
  // Si Odoo nos envía el contexto como un String, lo convertimos a Objeto
  if (typeof contextData === 'string') {
    try {
      contextData = JSON.parse(contextData);
    } catch (e) {
      contextData = { name: "Invitado" };
    }
  }

  let finalSpecialist = historyBody.active_specialist || "ventas";
  let detectedName = contextData.name || "Invitado";

  // Procesar resultado de la IA si existe
  if (nodeIA && nodeIA.isExecuted) {
    const rawText = (nodeIA.first().json.text || "{}");
    const cleanJson = rawText.replace(/```json/g, "").replace(/```/g, "").trim();
    try {
      const iaResult = JSON.parse(cleanJson);
      if (iaResult.nombre_detectado && iaResult.nombre_detectado !== "Invitado") {
        detectedName = iaResult.nombre_detectado;
      }
      finalSpecialist = iaResult.categoria || finalSpecialist;
    } catch (err) { /* ignore */ }
  }

  return [{
    json: {
      specialist: finalSpecialist.toLowerCase().trim(),
      history: historyBody.body || "",
      res_id: webhookBody.res_id || 0,
      context_data: contextData // Ahora es un objeto limpio
    }
  }];
} catch (error) {
  return [{ json: { error: error.message, location: "Preparar_Datos_Especialista" } }];
}

try {
  const webhookData = $node["Webhook"].json.body || {};
  const response = $node["Obtener_Mensajes_Odoo_V2"].json || {};
  const messages = (response.result && response.result.result) ? response.result.result : [];

  // 1. Filtrado de mensajes del sistema (OdooBot, notificaciones, etc.)
  const botPartnerId = 43; // Reemplaza por tu ID de Partner Bot si es distinto

  const relevantMessages = messages.filter(m => {
    const body = m.body || "";
    if (body.includes("o_mail_notification") || body.includes("abandonó la conversación")) return false;
    if (Array.isArray(m.author_id) && m.author_id[0] === botPartnerId) return false;
    return true;
  }).sort((a, b) => a.id - b.id);

  // 2. Agrupación con roles claros
  const groupedBody = relevantMessages.map(m => {
    let emisor = "Usuario";
    if (Array.isArray(m.author_id) && m.author_id[1]) emisor = m.author_id[1];
    else if (Array.isArray(m.author_guest_id) && m.author_guest_id[1]) emisor = m.author_guest_id[1];

    // Limpieza agresiva de HTML de Odoo
    const textoLimpio = (m.body || "")
      .replace(/<[^>]*>/g, "")
      .replace(/&nbsp;/g, " ")
      .replace(/\n/g, " ")
      .trim();

    return `${emisor.toUpperCase()}: ${textoLimpio}`;
  }).join("\n");

  return [{ json: { 
    body: { 
      body: groupedBody, 
      res_id: webhookData.res_id || 0, 
      active_specialist: String(webhookData.active_specialist || "false").toLowerCase() 
    } 
  } }];
} catch (error) {
  return [{ json: { error: error.message } }];
}

try {
  const nodeIA = $node["IA_Analisis_Total"];
  const nodeWebhook = $node["Webhook"];
  const rawText = (nodeIA && nodeIA.json) ? (nodeIA.json.text || "{}") : "{}";
  const webhookBody = (nodeWebhook && nodeWebhook.json && nodeWebhook.json.body) ? nodeWebhook.json.body : {};

  // Limpieza de Markdown y espacios
  const cleanJson = rawText.replace(/```json/g, "").replace(/```/g, "").trim();
  let ia = JSON.parse(cleanJson);

  // Validamos que el nombre no sea literalmente "Visitante"
  let nombreReal = ia.nombre_detectado;
  if (nombreReal && (nombreReal.toLowerCase() === "visitante" || nombreReal.toLowerCase() === "invitado")) {
      nombreReal = "Invitado"; 
  }

  return [{
    json: {
      jsonrpc: "2.0",
      params: {
        channel_id: parseInt(webhookBody.res_id || 0),
        specialist_id: "bot",
        token: "={{ $env.ELANTAR_BRIDGE_TOKEN }}",
        context_data: {
          name: nombreReal,
          city: ia.city || "unknown",
          idioma: ia.idioma || "Español",
          concerns: ia.resumen || "Sin resumen",
          categoria: ia.categoria || "general",
          last_update: new Date().toISOString()
        }
      }
    }
  }];
} catch (error) {
  return [{ json: { error: error.message, location: "Parsear_IA" } }];
}
